public boolean isPalindrome(String s) {
    int i = 0, j = s.length() - 1;
    while (i < j) {
        while (i < j && !Character.isLetterOrDigit(s.charAt(i))) i++;
        while (i < j && !Character.isLetterOrDigit(s.charAt(j))) j--;
        if (Character.toLowerCase(s.charAt(i)) != Character.toLowerCase(s.charAt(j))) return false;
        i++; j--;
    }
    return true;
}

public boolean isPalindrome(String s) {
    String cleaned = "";
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (Character.isLetterOrDigit(c)) cleaned = cleaned + Character.toLowerCase(c);
    }
    return cleaned == new StringBuilder(cleaned).reverse().toString();
}

class LRUCache<K, V> {
    private store = new Map<K, V>();
    constructor(private capacity: number) {}
    get(key: K): V | undefined {
        if (!this.store.has(key)) return undefined;
        const value = this.store.get(key)!;
        this.store.delete(key); this.store.set(key, value);
        return value;
    }
    put(key: K, value: V): void {
        if (this.store.has(key)) this.store.delete(key);
        this.store.set(key, value);
        if (this.store.size > this.capacity) {
            const oldest = this.store.keys().next().value as K;
            this.store.delete(oldest);
        }
    }
    size(): number { return this.store.size; }
}

class LRUCache<K, V> {
    private keys: K[] = [];
    private values: Map<K, V> = new Map();
    constructor(private capacity: number) {}
    get(key: K): V | undefined { return this.values.get(key); }
    put(key: K, value: V): void {
        if (this.values.has(key)) {
            this.keys.splice(this.keys.indexOf(key), 1);
        }
        this.keys.push(key);
        this.values.set(key, value);
        if (this.keys.length > this.capacity) {
            const oldest = this.keys.shift()!;
            this.values.delete(oldest);
        }
    }
    size(): number { return this.keys.length; }
}

#include <vector>
#include <queue>
#include <climits>
std::vector<long long> dijkstra(int n,
        const std::vector<std::vector<std::pair<int,int>>>& graph,
        int source) {
    std::vector<long long> dist(n, LLONG_MAX);
    using PQ = std::pair<long long,int>;
    std::priority_queue<PQ, std::vector<PQ>, std::greater<PQ>> pq;
    dist[source] = 0;
    pq.emplace(0LL, source);
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        if (d > dist[u]) continue;
        for (auto [v, w] : graph[u]) {
            long long nd = d + w;
            if (nd < dist[v]) { dist[v] = nd; pq.emplace(nd, v); }
        }
    }
    return dist;
}

#include <vector>
#include <climits>
std::vector<long long> dijkstra(int n,
        const std::vector<std::vector<std::pair<int,int>>>& graph,
        int source) {
    std::vector<long long> dist(n, LLONG_MAX);
    std::vector<bool> visited(n, false);
    dist[source] = 0;
    for (int i = 0; i < n; i++) {
        int u = -1;
        long long best = LLONG_MAX;
        for (int j = 0; j < n; j++)
            if (!visited[j] && dist[j] < best) { best = dist[j]; u = j; }
        if (u == -1) break;
        visited[u] = true;
        for (auto& e : graph[u]) {
            long long nd = dist[u] + e.second;
            if (nd < dist[e.first]) dist[e.first] = nd;
        }
    }
    return dist;
}

