public class BST {
    private static class Node { int key; Node left, right; Node(int k){key=k;} }
    private Node root; private int n;
    public void insert(int key) { root = insert(root, key); }
    private Node insert(Node node, int key) {
        if (node == null) { n++; return new Node(key); }
        if (key < node.key) node.left = insert(node.left, key);
        else if (key > node.key) node.right = insert(node.right, key);
        return node;
    }
    public boolean contains(int key) {
        Node x = root;
        while (x != null) {
            if (key < x.key) x = x.left;
            else if (key > x.key) x = x.right;
            else return true;
        }
        return false;
    }
    public boolean delete(int key) {
        if (!contains(key)) return false;
        root = delete(root, key); n--; return true;
    }
    private Node delete(Node node, int key) {
        if (key < node.key) node.left = delete(node.left, key);
        else if (key > node.key) node.right = delete(node.right, key);
        else {
            if (node.left == null) return node.right;
            if (node.right == null) return node.left;
            Node succ = node.right; while (succ.left != null) succ = succ.left;
            node.key = succ.key;
            node.right = delete(node.right, succ.key);
        }
        return node;
    }
    public List<Integer> inorder() {
        List<Integer> out = new ArrayList<>();
        inorder(root, out); return out;
    }
    private void inorder(Node node, List<Integer> out) {
        if (node == null) return;
        inorder(node.left, out); out.add(node.key); inorder(node.right, out);
    }
    public int size() { return n; }
}

import java.util.*;
public class BST {
    public static class Node { public int key; public Node left, right; }
    public Node root;
    public void insert(int key) {
        Node n = new Node(); n.key = key;
        if (root == null) { root = n; return; }
        Node cur = root;
        while (true) {
            if (key < cur.key) { if (cur.left==null){cur.left=n;return;} cur=cur.left; }
            else { if (cur.right==null){cur.right=n;return;} cur=cur.right; }
        }
    }
    public boolean contains(int key) {
        for (Node x = root; x != null; x = (key<x.key?x.left:x.right)) if (x.key==key) return true;
        return false;
    }
    public boolean delete(int key) {
        if (root == null) return false;
        if (root.key == key) { root = (root.left != null ? root.left : root.right); return true; }
        return false;
    }
    public ArrayList<Integer> inorder() {
        ArrayList<Integer> out = new ArrayList<>();
        walk(root, out); return out;
    }
    private void walk(Node x, ArrayList<Integer> out) {
        if (x == null) return;
        walk(x.left, out); out.add(x.key); walk(x.right, out);
    }
    public int size() {
        return sizeOf(root);
    }
    private int sizeOf(Node x) { return x == null ? 0 : 1 + sizeOf(x.left) + sizeOf(x.right); }
}

package pool
import "sync"
type job[T any] struct { idx int; val T }
func ParallelMap[T, R any](inputs []T, workers int, fn func(T) R) []R {
    if workers <= 0 { workers = 1 }
    if workers > len(inputs) { workers = len(inputs) }
    out := make([]R, len(inputs))
    if len(inputs) == 0 { return out }
    jobs := make(chan job[T])
    var wg sync.WaitGroup
    for w := 0; w < workers; w++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for j := range jobs { out[j.idx] = fn(j.val) }
        }()
    }
    for i, v := range inputs { jobs <- job[T]{i, v} }
    close(jobs)
    wg.Wait()
    return out
}

package pool
import "sync"
func ParallelMap[T, R any](inputs []T, workers int, fn func(T) R) []R {
    if workers <= 0 { workers = 1 }
    out := make([]R, len(inputs))
    var mu sync.Mutex
    var wg sync.WaitGroup
    for i, v := range inputs {
        wg.Add(1)
        go func() {
            defer wg.Done()
            r := fn(v)
            mu.Lock(); out[i] = r; mu.Unlock()
        }()
    }
    wg.Wait()
    return out
}
